bool FoodPantries::validateJsonForCreation(const Json::Value &pJson, std::string &err)
{
    if(pJson.isMember("id"))
    {
        if(!validJsonOfField(0, "id", pJson["id"], err, true))
            return false;
    }
    if(pJson.isMember("agency"))
    {
        if(!validJsonOfField(1, "agency", pJson["agency"], err, true))
            return false;
    }
    else
    {
        err="The agency column cannot be null";
        return false;
    }
    if(pJson.isMember("day_of_week"))
    {
        if(!validJsonOfField(2, "day_of_week", pJson["day_of_week"], err, true))
            return false;
    }
    else
    {
        err="The day_of_week column cannot be null";
        return false;
    }
    if(pJson.isMember("open_time"))
    {
        if(!validJsonOfField(3, "open_time", pJson["open_time"], err, true))
            return false;
    }
    if(pJson.isMember("close_time"))
    {
        if(!validJsonOfField(4, "close_time", pJson["close_time"], err, true))
            return false;
    }
    if(pJson.isMember("address"))
    {
        if(!validJsonOfField(5, "address", pJson["address"], err, true))
            return false;
    }
    if(pJson.isMember("latitude"))
    {
        if(!validJsonOfField(6, "latitude", pJson["latitude"], err, true))
            return false;
    }
    if(pJson.isMember("longitude"))
    {
        if(!validJsonOfField(7, "longitude", pJson["longitude"], err, true))
            return false;
    }
    if(pJson.isMember("meal_type"))
    {
        if(!validJsonOfField(8, "meal_type", pJson["meal_type"], err, true))
            return false;
    }
    if(pJson.isMember("frequency"))
    {
        if(!validJsonOfField(9, "frequency", pJson["frequency"], err, true))
            return false;
    }
    if(pJson.isMember("phone"))
    {
        if(!validJsonOfField(10, "phone", pJson["phone"], err, true))
            return false;
    }
    if(pJson.isMember("program"))
    {
        if(!validJsonOfField(11, "program", pJson["program"], err, true))
            return false;
    }
    return true;
}
